#!/usr/bin/env python3
"""ETL Pipeline Parser and Executor - validates, normalizes, and executes pipeline specifications."""

import json
import re
import sys
from dataclasses import dataclass
from typing import Any, Callable, Dict, List


class ETLError(Exception):
    def __init__(self, error_code: str, message: str, path: str):
        self.error_code = error_code
        self.message = message
        self.path = path
        super().__init__(message)


def _tokenize_expression(expr: str, path: str) -> List[str]:
    tokens = []
    i = 0
    expr = expr.strip()

    while i < len(expr):
        if expr[i].isspace():
            i += 1
        elif expr[i] == '"':
            j = i + 1
            while j < len(expr) and expr[j] != '"':
                if expr[j] == '\\' and j + 1 < len(expr):
                    j += 2
                else:
                    j += 1
            if j >= len(expr):
                raise ETLError('BAD_EXPR', 'ETL_ERROR: unterminated string literal', path)
            tokens.append(expr[i:j+1])
            i = j + 1
        elif expr[i] in '()':
            tokens.append(expr[i])
            i += 1
        elif expr[i].isdigit():
            j = i
            while j < len(expr) and (expr[j].isdigit() or expr[j] == '.'):
                j += 1
            tokens.append(expr[i:j])
            i = j
        elif expr[i].isalpha() or expr[i] == '_':
            j = i
            while j < len(expr) and (expr[j].isalnum() or expr[j] == '_'):
                j += 1
            tokens.append(expr[i:j])
            i = j
        elif i + 1 < len(expr) and expr[i:i+2] in ('>=', '<=', '==', '!=', '&&', '||'):
            tokens.append(expr[i:i+2])
            i += 2
        elif expr[i] == '.':
            tokens.append('.')
            i += 1
        elif expr[i] in '+-*/><!':
            if i + 1 < len(expr) and expr[i] == '*' and expr[i+1] == '*':
                raise ETLError('BAD_EXPR', "ETL_ERROR: unsupported operator '**'", path)
            tokens.append(expr[i])
            i += 1
        elif i + 1 < len(expr) and expr[i] == '^' and expr[i+1] == '^':
            raise ETLError('BAD_EXPR', "ETL_ERROR: unsupported operator '^^'", path)
        else:
            raise ETLError('BAD_EXPR', f"ETL_ERROR: invalid character '{expr[i]}' in expression", path)

    return tokens


@dataclass
class ASTNode:
    def evaluate(self, row: Dict[str, Any], params: Dict[str, Any] = None) -> Any:
        raise NotImplementedError()


@dataclass
class LiteralNode(ASTNode):
    value: Any

    def evaluate(self, row: Dict[str, Any], params: Dict[str, Any] = None) -> Any:
        return self.value


@dataclass
class IdentifierNode(ASTNode):
    name: str

    def evaluate(self, row: Dict[str, Any], params: Dict[str, Any] = None) -> Any:
        if self.name == 'params':
            return params
        return row.get(self.name)


@dataclass
class MemberAccessNode(ASTNode):
    obj: ASTNode
    member: str

    def evaluate(self, row: Dict[str, Any], params: Dict[str, Any] = None) -> Any:
        obj_val = self.obj.evaluate(row, params)
        if isinstance(obj_val, dict):
            return obj_val.get(self.member)
        return None


@dataclass
class UnaryOpNode(ASTNode):
    op: str
    operand: ASTNode

    def evaluate(self, row: Dict[str, Any], params: Dict[str, Any] = None) -> Any:
        val = self.operand.evaluate(row, params)
        if self.op == '!':
            return True if val is None else not bool(val)
        return None


def _safe_div(left, right):
    return None if right == 0 else left / right


_ARITH_OPS = {'+': lambda a, b: a + b, '-': lambda a, b: a - b,
              '*': lambda a, b: a * b, '/': _safe_div}

_COMPARE_OPS = {'==': lambda a, b: a == b, '!=': lambda a, b: a != b,
                '<': lambda a, b: a < b, '<=': lambda a, b: a <= b,
                '>': lambda a, b: a > b, '>=': lambda a, b: a >= b}


def _eval_arithmetic(op: str, left: Any, right: Any) -> Any:
    if not isinstance(left, (int, float)) or not isinstance(right, (int, float)):
        return None
    fn = _ARITH_OPS.get(op)
    return fn(left, right) if fn else None


def _eval_comparison(op: str, left: Any, right: Any) -> Any:
    if left is None or right is None:
        return False
    if not isinstance(left, (int, float, str)):
        return False
    if not (isinstance(left, (int, float)) and isinstance(right, (int, float))):
        if type(left) != type(right):
            return False
    fn = _COMPARE_OPS.get(op)
    return fn(left, right) if fn else False


@dataclass
class BinaryOpNode(ASTNode):
    op: str
    left: ASTNode
    right: ASTNode

    def evaluate(self, row: Dict[str, Any], params: Dict[str, Any] = None) -> Any:
        left_val = self.left.evaluate(row, params)
        right_val = self.right.evaluate(row, params)

        if self.op == '&&':
            if left_val is None or left_val is False:
                return False
            return right_val if right_val is not None else False
        if self.op == '||':
            if left_val is True:
                return True
            return right_val if right_val is not None else False

        if self.op in _ARITH_OPS:
            return _eval_arithmetic(self.op, left_val, right_val)
        if self.op in _COMPARE_OPS:
            return _eval_comparison(self.op, left_val, right_val)
        return None


class ExpressionParser:
    def __init__(self, tokens: List[str], path: str):
        self.tokens = tokens
        self.pos = 0
        self.path = path

    def parse(self) -> ASTNode:
        if not self.tokens:
            raise ETLError('BAD_EXPR', 'ETL_ERROR: empty expression', self.path)
        result = self._parse_or()
        if self.pos < len(self.tokens):
            remaining = ' '.join(self.tokens[self.pos:])
            raise ETLError('BAD_EXPR', f'ETL_ERROR: unexpected token after expression: {remaining}', self.path)
        return result

    def _current(self) -> str | None:
        return self.tokens[self.pos] if self.pos < len(self.tokens) else None

    def _consume(self) -> str:
        token = self.tokens[self.pos]
        self.pos += 1
        return token

    def _parse_or(self) -> ASTNode:
        left = self._parse_and()
        while self._current() in ('||', 'or'):
            op = self._consume()
            right = self._parse_and()
            left = BinaryOpNode(op, left, right)
        return left

    def _parse_and(self) -> ASTNode:
        left = self._parse_equality()
        while self._current() in ('&&', 'and'):
            op = self._consume()
            right = self._parse_equality()
            left = BinaryOpNode(op, left, right)
        return left

    def _parse_equality(self) -> ASTNode:
        left = self._parse_comparison()
        while self._current() in ('==', '!='):
            op = self._consume()
            right = self._parse_comparison()
            left = BinaryOpNode(op, left, right)
        return left

    def _parse_comparison(self) -> ASTNode:
        left = self._parse_additive()
        while self._current() in ('<', '<=', '>', '>='):
            op = self._consume()
            right = self._parse_additive()
            left = BinaryOpNode(op, left, right)
        return left

    def _parse_additive(self) -> ASTNode:
        left = self._parse_multiplicative()
        while self._current() in ('+', '-'):
            op = self._consume()
            right = self._parse_multiplicative()
            left = BinaryOpNode(op, left, right)
        return left

    def _parse_multiplicative(self) -> ASTNode:
        left = self._parse_unary()
        while self._current() in ('*', '/'):
            op = self._consume()
            right = self._parse_unary()
            left = BinaryOpNode(op, left, right)
        return left

    def _parse_unary(self) -> ASTNode:
        if self._current() == '!':
            op = self._consume()
            operand = self._parse_unary()
            return UnaryOpNode(op, operand)
        return self._parse_primary()

    def _parse_primary(self) -> ASTNode:
        token = self._current()

        if token is None:
            raise ETLError('BAD_EXPR', 'ETL_ERROR: unexpected end of expression', self.path)

        if token == '(':
            self._consume()
            node = self._parse_or()
            if self._current() != ')':
                raise ETLError('BAD_EXPR', 'ETL_ERROR: missing closing parenthesis', self.path)
            self._consume()
            return node

        if token == 'true':
            self._consume()
            return LiteralNode(True)

        if token == 'false':
            self._consume()
            return LiteralNode(False)

        if token == 'null':
            self._consume()
            return LiteralNode(None)

        if token.startswith('"'):
            self._consume()
            content = token[1:-1]
            content = content.replace('\\"', '"').replace('\\\\', '\\').replace('\\n', '\n').replace('\\t', '\t')
            return LiteralNode(content)

        if token[0].isdigit():
            self._consume()
            try:
                return LiteralNode(float(token) if '.' in token else int(token))
            except ValueError:
                raise ETLError('BAD_EXPR', f'ETL_ERROR: invalid number format: {token}', self.path)

        if token[0].isalpha() or token[0] == '_':
            self._consume()
            node = IdentifierNode(token)
            while self._current() == '.':
                self._consume()
                member = self._current()
                if member is None or not (member[0].isalpha() or member[0] == '_'):
                    raise ETLError('BAD_EXPR', 'ETL_ERROR: expected identifier after "."', self.path)
                self._consume()
                node = MemberAccessNode(node, member)
            return node

        raise ETLError('BAD_EXPR', f'ETL_ERROR: unexpected token: {token}', self.path)


def parse_expression(expr: str, path: str) -> ASTNode:
    tokens = _tokenize_expression(expr, path)
    return ExpressionParser(tokens, path).parse()


def evaluate_expression(expr: str, row: Dict[str, Any], path: str, params: Dict[str, Any] = None) -> Any:
    return parse_expression(expr, path).evaluate(row, params)


def _require_string_field(step: Dict[str, Any], field: str, path: str) -> str:
    if field not in step:
        raise ETLError('MISSING_COLUMN',
                       f'ETL_ERROR: missing required field "{field}"', f'{path}.{field}')
    value = step[field]
    if not isinstance(value, str):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       f'ETL_ERROR: {field} must be a string', f'{path}.{field}')
    trimmed = value.strip()
    if not trimmed:
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       f'ETL_ERROR: {field} cannot be empty', f'{path}.{field}')
    return trimmed


def _normalize_select(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    if 'columns' not in step:
        raise ETLError('MISSING_COLUMN',
                       'ETL_ERROR: missing required field "columns"', f'{path}.columns')
    columns = step['columns']
    if not isinstance(columns, list):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       'ETL_ERROR: columns must be an array', f'{path}.columns')
    for i, col in enumerate(columns):
        if not isinstance(col, str):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: column names must be strings', f'{path}.columns[{i}]')
    return {'columns': columns}


def _normalize_filter(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    where = _require_string_field(step, 'where', path)
    parse_expression(where, f'{path}.where')
    return {'where': where}


def _normalize_map(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    as_val = _require_string_field(step, 'as', path)
    expr = _require_string_field(step, 'expr', path)
    parse_expression(expr, f'{path}.expr')
    return {'as': as_val, 'expr': expr}


def _normalize_rename(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    if 'mapping' in step:
        mapping = step['mapping']
        if not isinstance(mapping, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: mapping must be an object', f'{path}.mapping')
        for k, v in mapping.items():
            if not isinstance(k, str) or not isinstance(v, str):
                raise ETLError('SCHEMA_VALIDATION_FAILED',
                               'ETL_ERROR: mapping keys and values must be strings',
                               f'{path}.mapping')
        return {'mapping': mapping}

    if 'from' not in step or 'to' not in step:
        raise ETLError('MISSING_COLUMN',
                       'ETL_ERROR: rename requires either from/to or mapping', path)

    from_val = _require_string_field(step, 'from', path)
    to_val = _require_string_field(step, 'to', path)
    return {'mapping': {from_val: to_val}}


def _normalize_limit(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    if 'n' not in step:
        raise ETLError('MISSING_COLUMN',
                       'ETL_ERROR: missing required field "n"', f'{path}.n')
    n = step['n']
    if not isinstance(n, int) or isinstance(n, bool):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       'ETL_ERROR: n must be an integer', f'{path}.n')
    if n < 0:
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       'ETL_ERROR: n must be >= 0', f'{path}.n')
    return {'n': n}


def _normalize_branch(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    if 'branches' not in step:
        raise ETLError('MISSING_COLUMN',
                       'ETL_ERROR: missing required field "branches"', f'{path}.branches')
    branches = step['branches']
    if not isinstance(branches, list):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       'ETL_ERROR: branches must be an array', f'{path}.branches')
    if not branches:
        raise ETLError('MALFORMED_STEP',
                       'ETL_ERROR: branches cannot be empty', f'{path}.branches')

    normalized_branches = []
    otherwise_count = 0

    for i, branch in enumerate(branches):
        branch_path = f'{path}.branches[{i}]'

        if not isinstance(branch, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: branch must be an object', branch_path)

        normalized_branch = {}

        if 'id' in branch:
            id_val = branch['id']
            if not isinstance(id_val, str):
                raise ETLError('SCHEMA_VALIDATION_FAILED',
                               'ETL_ERROR: id must be a string', f'{branch_path}.id')
            normalized_branch['id'] = id_val

        if 'when' not in branch:
            raise ETLError('MISSING_COLUMN',
                           'ETL_ERROR: missing required field "when"', f'{branch_path}.when')
        when = branch['when']
        if not isinstance(when, str):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: when must be a string', f'{branch_path}.when')

        if when == 'otherwise':
            if i != len(branches) - 1:
                raise ETLError('MALFORMED_STEP',
                               'ETL_ERROR: otherwise branch must be last', f'{path}.branches')
            otherwise_count += 1
            normalized_branch['when'] = 'otherwise'
        else:
            trimmed_when = when.strip()
            if not trimmed_when:
                raise ETLError('SCHEMA_VALIDATION_FAILED',
                               'ETL_ERROR: when cannot be empty', f'{branch_path}.when')
            parse_expression(trimmed_when, f'{branch_path}.when')
            normalized_branch['when'] = trimmed_when

        if 'steps' not in branch:
            raise ETLError('MISSING_COLUMN',
                           'ETL_ERROR: missing required field "steps"', f'{branch_path}.steps')
        steps = branch['steps']
        if not isinstance(steps, list):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: steps must be an array', f'{branch_path}.steps')

        normalized_branch['steps'] = [normalize_step(sub_step, j, branch_path) for j, sub_step in enumerate(steps)]
        normalized_branches.append(normalized_branch)

    if otherwise_count > 1:
        raise ETLError('MALFORMED_STEP',
                       'ETL_ERROR: at most one otherwise branch allowed', f'{path}.branches')

    strategy = 'concat'
    if 'merge' in step:
        merge = step['merge']
        if not isinstance(merge, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: merge must be an object', f'{path}.merge')
        strategy = merge.get('strategy', 'concat')
        if not isinstance(strategy, str):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: strategy must be a string', f'{path}.merge.strategy')
        if strategy != 'concat':
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           f'ETL_ERROR: unsupported merge strategy "{strategy}"', f'{path}.merge.strategy')

    return {'branches': normalized_branches, 'merge': {'strategy': strategy}}


def _normalize_call(step: Dict[str, Any], path: str) -> Dict[str, Any]:
    if 'name' not in step:
        raise ETLError('MISSING_COLUMN',
                       'ETL_ERROR: missing required field "name"', f'{path}.name')
    name = step['name']
    if not isinstance(name, str):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       'ETL_ERROR: name must be a string', f'{path}.name')
    if not re.match(r'^[A-Za-z_][A-Za-z0-9_]*$', name):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       f'ETL_ERROR: invalid definition name "{name}"', f'{path}.name')
    params = step.get('params', {})
    if not isinstance(params, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED',
                       'ETL_ERROR: params must be an object', f'{path}.params')
    for k, v in params.items():
        if not isinstance(k, str):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           'ETL_ERROR: param keys must be strings', f'{path}.params')
        if isinstance(v, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED',
                           f'ETL_ERROR: param "{k}" must be a scalar or array', f'{path}.params.{k}')
        if isinstance(v, list):
            for idx, item in enumerate(v):
                if isinstance(item, (dict, list)):
                    raise ETLError('SCHEMA_VALIDATION_FAILED',
                                   f'ETL_ERROR: param "{k}[{idx}]" must be a scalar', f'{path}.params.{k}[{idx}]')
    return {'name': name, 'params': params}


_OP_NORMALIZERS: Dict[str, Callable[[Dict[str, Any], str], Dict[str, Any]]] = {
    'branch': _normalize_branch,
    'call': _normalize_call,
    'filter': _normalize_filter,
    'limit': _normalize_limit,
    'map': _normalize_map,
    'rename': _normalize_rename,
    'select': _normalize_select,
}


def normalize_step(step: Dict[str, Any], index: int, parent_path: str = None) -> Dict[str, Any]:
    path = f'{parent_path}.steps[{index}]' if parent_path else f'pipeline.steps[{index}]'

    if not isinstance(step, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: step must be an object', path)

    op_raw = step.get('op')
    if op_raw is None:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: missing required field "op"', path)
    if not isinstance(op_raw, str):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: op must be a string', f'{path}.op')

    op = op_raw.strip().lower()
    if not op:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: op cannot be empty', f'{path}.op')

    if op not in _OP_NORMALIZERS:
        raise ETLError('UNKNOWN_OP', f'ETL_ERROR: unsupported op \'{op}\'', f'{path}.op')

    normalized = _OP_NORMALIZERS[op](step, path)
    return {'op': op, **{k: normalized[k] for k in sorted(normalized)}}


def _exec_select(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str, **kwargs) -> List[Dict[str, Any]]:
    columns = step['columns']
    result = []
    for row in rows:
        new_row = {}
        for i, col in enumerate(columns):
            if col not in row:
                raise ETLError('MISSING_COLUMN',
                               f"ETL_ERROR: column '{col}' not found in row",
                               f'{path}.columns[{i}]')
            new_row[col] = row[col]
        result.append(new_row)
    return result


def _exec_filter(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str, exec_context: dict = None, **kwargs) -> List[Dict[str, Any]]:
    where = step['where']
    params = exec_context.get('params', {}) if exec_context else {}
    return [row for row in rows if (val := evaluate_expression(where, row, f'{path}.where', params)) is not None and val is not False]


def _exec_map(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str, exec_context: dict = None, **kwargs) -> List[Dict[str, Any]]:
    as_field = step['as']
    expr = step['expr']
    params = exec_context.get('params', {}) if exec_context else {}
    result = []
    for row in rows:
        new_row = row.copy()
        new_row[as_field] = evaluate_expression(expr, row, f'{path}.expr', params)
        result.append(new_row)
    return result


def _exec_rename(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str, **kwargs) -> List[Dict[str, Any]]:
    mapping = step['mapping']
    result = []
    for row in rows:
        new_row = row.copy()
        for src, dst in mapping.items():
            if src not in new_row:
                raise ETLError('MISSING_COLUMN',
                               f"ETL_ERROR: column '{src}' not found in row",
                               f'{path}.mapping.{src}')
            new_row[dst] = new_row[src]
            if dst != src:
                del new_row[src]
        result.append(new_row)
    return result


def _exec_limit(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str, **kwargs) -> List[Dict[str, Any]]:
    return rows[:step['n']]


def _execute_steps(rows: List[Dict[str, Any]], steps: List[Dict[str, Any]], base_path: str,
                   defs: Dict[str, Any], call_stack: set, exec_context: dict = None) -> List[Dict[str, Any]]:
    """Execute a sequence of steps with unified error handling."""
    if exec_context is None:
        exec_context = {}
    for j, sub_step in enumerate(steps):
        sub_path = f'{base_path}.steps[{j}]'
        sub_op = sub_step['op']
        executor = _OP_EXECUTORS.get(sub_op)
        if executor is None:
            raise ETLError('UNKNOWN_OP', f'ETL_ERROR: unsupported op \'{sub_op}\'', f'{sub_path}.op')
        try:
            rows = executor(rows, sub_step, sub_path, defs=defs, call_stack=call_stack, exec_context=exec_context)
        except ETLError:
            raise
        except Exception as e:
            raise ETLError('EXECUTION_FAILED', f'ETL_ERROR: {e}', sub_path) from e
    return rows


def _exec_call(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str,
               defs: Dict[str, Any], call_stack: set, exec_context: dict) -> List[Dict[str, Any]]:
    name = step['name']
    params = step.get('params', {})

    if name not in defs:
        raise ETLError('UNKNOWN_DEF', f'ETL_ERROR: definition "{name}" not found', f'{path}.name')

    if name in call_stack:
        raise ETLError('RECURSION_FORBIDDEN', f'ETL_ERROR: recursive call to "{name}"', f'{path}.name')

    def_steps = defs[name].get('steps', [])
    return _execute_steps(rows, def_steps, f'defs[{name}]', defs, call_stack | {name}, {'params': params})


def _exec_branch(rows: List[Dict[str, Any]], step: Dict[str, Any], path: str,
                 defs: Dict[str, Any], call_stack: set, exec_context: dict) -> List[Dict[str, Any]]:
    branches = step['branches']
    branch_buckets: Dict[int, List[Dict[str, Any]]] = {i: [] for i in range(len(branches))}

    for row in rows:
        for i, branch in enumerate(branches):
            when = branch['when']
            if when == 'otherwise' or (val := evaluate_expression(when, row, f'{path}.branches[{i}].when')) is not None and val is not False:
                branch_buckets[i].append(row)
                break

    result = []
    for i, branch in enumerate(branches):
        branch_rows = branch_buckets[i]
        if branch_rows:
            branch_rows = _execute_steps(branch_rows, branch['steps'], f'{path}.branches[{i}]', defs, call_stack, exec_context)
            result.extend(branch_rows)

    return result


_OP_EXECUTORS: Dict[str, Callable] = {
    'branch': _exec_branch,
    'call': _exec_call,
    'filter': _exec_filter,
    'limit': _exec_limit,
    'map': _exec_map,
    'rename': _exec_rename,
    'select': _exec_select,
}


def execute_pipeline(steps: List[Dict[str, Any]], dataset: List[Dict[str, Any]],
                     defs: Dict[str, Any] = None) -> tuple[list[Dict[str, Any]], Dict[str, int]]:
    defs = defs or {}
    rows = [row.copy() for row in dataset]
    rows_in = len(rows)
    rows = _execute_steps(rows, steps, 'pipeline', defs, set())
    return rows, {'rows_in': rows_in, 'rows_out': len(rows)}


def _resolve_lib_ref(ref: str, library: Dict[str, Any], path: str) -> tuple[str, str, Dict[str, Any]]:
    """
    Resolve a library reference string like "ns:name" to (namespace, name, steps).
    Returns (namespace_name, def_name, def_steps).
    Raises ETLError with UNKNOWN_NAMESPACE or UNKNOWN_LIB_REF if not found.
    """
    if ':' not in ref:
        raise ETLError('UNKNOWN_LIB_REF', f'ETL_ERROR: invalid reference format "{ref}"', path)

    parts = ref.split(':', 1)
    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise ETLError('UNKNOWN_LIB_REF', f'ETL_ERROR: invalid reference format "{ref}"', path)

    ns_name, def_name = parts

    if ns_name not in library:
        raise ETLError('UNKNOWN_NAMESPACE', f'ETL_ERROR: namespace "{ns_name}" not found in library', path)

    ns = library[ns_name]
    if not isinstance(ns, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: namespace "{ns_name}" must be an object', f'library.{ns_name}')

    defs = ns.get('defs', {})
    if not isinstance(defs, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: defs in namespace "{ns_name}" must be an object', f'library.{ns_name}.defs')

    if def_name not in defs:
        raise ETLError('UNKNOWN_LIB_REF', f'ETL_ERROR: definition "{def_name}" not found in namespace "{ns_name}"', path)

    def_val = defs[def_name]
    if not isinstance(def_val, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: definition "{def_name}" must be an object', f'library.{ns_name}.defs.{def_name}')

    return ns_name, def_name, def_val


def _normalize_compose_item(item: Any, index: int, library: Dict[str, Any], parent_path: str) -> tuple[Dict[str, Any], List[Dict[str, Any]]]:
    """
    Normalize a single compose item.
    Returns (params_dict, steps_list) where steps_list is the expanded steps.
    """
    path = f'{parent_path}[{index}]'

    if not isinstance(item, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: compose item must be an object', path)

    has_ref = 'ref' in item
    has_steps = 'steps' in item

    if has_ref and has_steps:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: compose item cannot have both "ref" and "steps"', path)

    if not has_ref and not has_steps:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: compose item must have either "ref" or "steps"', path)

    if has_ref:
        ref = item['ref']
        if not isinstance(ref, str):
            raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: ref must be a string', f'{path}.ref')

        params = item.get('params', {})
        if not isinstance(params, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: params must be an object', f'{path}.params')

        ns_name, def_name, def_val = _resolve_lib_ref(ref, library, f'{path}.ref')

        if 'steps' not in def_val:
            raise ETLError('MISSING_COLUMN', f'ETL_ERROR: missing required field "steps"', f'library.{ns_name}.defs.{def_name}.steps')

        def_steps = def_val['steps']
        if not isinstance(def_steps, list):
            raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: steps must be an array', f'library.{ns_name}.defs.{def_name}.steps')

        normalized_steps = [normalize_step(step, j, f'library.{ns_name}.defs.{def_name}') for j, step in enumerate(def_steps)]

        return params, normalized_steps

    steps = item['steps']
    if not isinstance(steps, list):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: steps must be an array', f'{path}.steps')

    normalized_steps = [normalize_step(step, j, path) for j, step in enumerate(steps)]

    return {}, normalized_steps


def _normalize_library(library: Any) -> Dict[str, Any]:
    if not isinstance(library, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: library must be an object', 'library')

    normalized_library = {}
    for ns_name, ns_val in library.items():
        ns_path = f'library.{ns_name}'
        if not isinstance(ns_val, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: namespace "{ns_name}" must be an object', ns_path)

        defs = ns_val.get('defs', {})
        if not isinstance(defs, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: defs must be an object', f'{ns_path}.defs')

        normalized_defs = {}
        for def_name, def_val in defs.items():
            def_path = f'{ns_path}.defs.{def_name}'
            if not isinstance(def_val, dict):
                raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: definition "{def_name}" must be an object', def_path)

            if 'steps' not in def_val:
                raise ETLError('MISSING_COLUMN', f'ETL_ERROR: missing required field "steps"', f'{def_path}.steps')

            def_steps = def_val['steps']
            if not isinstance(def_steps, list):
                raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: steps must be an array', f'{def_path}.steps')

            normalized_steps = [normalize_step(s, j, def_path) for j, s in enumerate(def_steps)]
            normalized_defs[def_name] = {'steps': normalized_steps}

        normalized_library[ns_name] = {'defs': normalized_defs}

    return normalized_library


def _normalize_compose(compose: Any, library: Dict[str, Any]) -> List[tuple[Dict[str, Any], List[Dict[str, Any]]]]:
    if not isinstance(compose, list):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: compose must be an array', 'compose')

    if not compose:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: compose cannot be empty', 'compose')

    result = []
    for i, item in enumerate(compose):
        params, steps = _normalize_compose_item(item, i, library, 'compose')
        result.append((params, steps))

    return result


def process_pipeline(data: Dict[str, Any], execute: bool = False) -> Dict[str, Any]:
    if not isinstance(data, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: input must be a JSON object', '')

    has_library = 'library' in data
    has_compose = 'compose' in data
    has_pipeline = 'pipeline' in data

    if 'dataset' not in data:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: missing required field "dataset"', 'dataset')

    dataset = data['dataset']
    if not isinstance(dataset, list):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: dataset must be an array', 'dataset')
    for i, item in enumerate(dataset):
        if not isinstance(item, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: dataset items must be objects', f'dataset[{i}]')

    normalized_library = {}
    if has_library:
        normalized_library = _normalize_library(data['library'])

    if has_compose and has_pipeline:
        pipeline = data['pipeline']
        if isinstance(pipeline, dict) and 'steps' in pipeline:
            raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: compose and pipeline.steps are mutually exclusive', 'compose')

    if has_compose:
        # Process compose
        compose_items = _normalize_compose(data['compose'], normalized_library)

        if execute:
            # Execute with params passed to each step group
            rows = [row.copy() for row in dataset]
            rows_in = len(rows)

            for params, steps in compose_items:
                exec_ctx = {'params': params if params else {}}
                rows = _execute_steps(rows, steps, 'compose', {}, set(), exec_ctx)

            return {'status': 'ok', 'data': rows, 'metrics': {'rows_in': rows_in, 'rows_out': len(rows)}}

        # Normalize mode: flatten steps, keeping params expressions as-is
        all_steps = []
        for params, steps in compose_items:
            all_steps.extend(steps)
        return {'status': 'ok', 'normalized': {'steps': all_steps}}

    # Original pipeline processing
    if 'pipeline' not in data:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: missing required field "pipeline"', 'pipeline')

    pipeline = data['pipeline']
    if not isinstance(pipeline, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: pipeline must be an object', 'pipeline')

    if 'steps' not in pipeline:
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: missing required field "steps"', 'pipeline.steps')
    steps = pipeline['steps']
    if not isinstance(steps, list):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: steps must be an array', 'pipeline.steps')

    normalized_defs = {}
    defs = data.get('defs', {})
    if not isinstance(defs, dict):
        raise ETLError('SCHEMA_VALIDATION_FAILED', 'ETL_ERROR: defs must be an object', 'defs')
    for def_name, def_val in defs.items():
        def_path = f'defs[{def_name}]'
        if not isinstance(def_val, dict):
            raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: definition "{def_name}" must be an object', def_path)
        if 'steps' not in def_val:
            raise ETLError('MISSING_COLUMN', f'ETL_ERROR: missing required field "steps"', f'{def_path}.steps')
        def_steps = def_val['steps']
        if not isinstance(def_steps, list):
            raise ETLError('SCHEMA_VALIDATION_FAILED', f'ETL_ERROR: steps must be an array', f'{def_path}.steps')
        normalized_defs[def_name] = {'steps': [normalize_step(s, j, def_path) for j, s in enumerate(def_steps)]}

    normalized_steps = [normalize_step(s, i) for i, s in enumerate(steps)]

    if execute:
        result_rows, metrics = execute_pipeline(normalized_steps, dataset, defs=normalized_defs)
        return {'status': 'ok', 'data': result_rows, 'metrics': metrics}
    return {'status': 'ok', 'normalized': {'steps': normalized_steps}}


def main():
    args = sys.argv[1:]
    execute = False

    i = 0
    while i < len(args):
        arg = args[i]
        if arg == '--execute':
            if i + 1 < len(args) and args[i + 1].lower() in ('true', 'false'):
                execute = args[i + 1].lower() == 'true'
                i += 2
            else:
                execute = True
                i += 1
        else:
            i += 1

    try:
        data = json.loads(sys.stdin.read())
    except json.JSONDecodeError as e:
        print(json.dumps({
            'status': 'error',
            'error_code': 'SCHEMA_VALIDATION_FAILED',
            'message': f'ETL_ERROR: invalid JSON: {e}',
            'path': ''
        }))
        sys.exit(1)

    try:
        result = process_pipeline(data, execute=execute)
        print(json.dumps(result))
    except ETLError as e:
        print(json.dumps({
            'status': 'error',
            'error_code': e.error_code,
            'message': e.message,
            'path': e.path
        }))
        sys.exit(1)


if __name__ == '__main__':
    main()

